            //
            aOrbiterJ = (aOrbiterJ + aOrbiterI) + 14777886290921517883U;
            aOrbiterK = (((aOrbiterK ^ aOrbiterJ) ^ 8465379083302915881U) ^ aOrbiterUpdateSaltF[(((31U - aIndex) + 21U)) & S_SALT1]) ^ aNonceWordN;
            aOrbiterK = RotL64((aOrbiterK * 5946076808174772459U), 19U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterJ) + 7738443393260273307U) + aOrbiterUpdateSaltD[((aIndex + 29U)) & S_SALT1];
