            aCross = RotL64(aScrapLaneA[((S_BLOCK1 - aIndex + 9319U)) & S_BLOCK1], 39U) ^ RotL64(pSnow[((S_BLOCK1 - aIndex + 6035U)) & S_BLOCK1], 10U);
