            aOrbiterI = (((aWandererE + RotL64(aPrevious, 20U)) + 7056531787483200759U) + aOrbiterAssignSaltF[(((31U - aIndex) + 22U)) & S_SALT1]) + aNonceWordC;
            aOrbiterH = (((aWandererB + RotL64(aScatter, 5U)) + RotL64(aCarry, 5U)) + 2376626637681377773U) + aNonceWordH;
            aOrbiterA = ((aWandererI + RotL64(aCross, 11U)) + RotL64(aCarry, 51U)) + 7903485357407688567U;
