            //
            aOrbiterE = (aOrbiterE + aOrbiterJ) + 8665170682727599108U;
            aOrbiterB = (aOrbiterB ^ aOrbiterE) ^ 4874348112964320111U;
            aOrbiterB = RotL64((aOrbiterB * 12514221090238586603U), 5U);
